const payload = $input.item.json.payload || [];
const incoming = payload.filter(function(m) { return m.message_type === 0; }).sort(function(a, b) { return b.created_at - a.created_at; });
const lastId = incoming[0] ? incoming[0].id.toString() : '';
const webhookId = $('Verificar Condições1').item.json.messageId;
const now = Math.floor(Date.now() / 1000);
const recent = incoming.filter(function(m) { return (now - m.created_at) < 10; }).map(function(m) { return (m.processed_message_content || m.content || '').replace(/<[^>]*>/g, '').trim(); }).filter(function(m) { return m.length > 0; }).reverse();
const msg = recent.length > 0 ? recent.join(' ') : $('Verificar Condições1').item.json.content || '';
return [{ json: { isLastMessage: lastId === webhookId, lastMessageId: lastId, webhookMessageId: webhookId, combinedMessage: msg, totalPayload: payload.length, conversationId: $('Verificar Condições1').item.json.conversationId } }];

const body = $input.item.json.body;

const event = body.event || '';
const messageType = body.message_type || '';
const assignee = body.conversation?.meta?.assignee;
const senderType = body.conversation?.messages?.[0]?.sender?.type || '';

const isMessageCreated = event === 'message_created';
const isIncoming = messageType === 'incoming';
const isFromContact = senderType === 'contact';
const noAssignee = assignee === null || assignee === undefined;

const shouldProcess = isMessageCreated && isIncoming && isFromContact && noAssignee;

const conversationId = body.conversation?.id?.toString() || '';
const messageId = body.id?.toString() || '';
const content = (body.content || '').replace(/<[^>]*>/g, '').trim();

return [{ json: {
  ...body,
  shouldProcess,
  conversationId,
  messageId,
  content
} }];
